{
  "command": "cp pre-commit .git/hooks/pre-commit",
  "description": "Install pre-commit hook in git hooks"
}

{
  "command": "echo \"test with trailing space \" > /tmp/test.txt && git add /tmp/test.txt && ./pre-commit && rm -f /tmp/test.txt",
  "description": "Test pre-commit hook with trailing whitespace"
}

{
  "command": "echo \"print('debug message')\" > /tmp/test.py && ./pre-commit 2>&1 | grep -E \"(ERROR|trailing whitespace|debug)\" && rm -f /tmp/test.py",
  "description": "Test pre-commit hook with debug print"
}
